def score_project(spec):
    score = 0
    if spec.get("volume_per_day", 0) >= 10:
        score += 20
    if spec.get("output_schema_defined", False):
        score += 20
    if spec.get("has_rubric", False):
        score += 20
    users = spec.get("users_count", 0)
    if 1 <= users <= 10:
        score += 20
    if spec.get("eval_method_defined", False):
        score += 20
    if score >= 80:
        verdict = "ship it"
    elif score >= 60:
        verdict = "narrow the scope"
    elif score >= 40:
        verdict = "pick something else"
    else:
        verdict = "don't build this"
    return {"score": score, "verdict": verdict}

