import os
os.environ["ANTHROPIC_API_KEY"] = "sk-ant-test-deterministic"

TOOLS = {
    "search": lambda q: f"results for {q}",
}

class MockTextBlock:
    def __init__(self, text):
        self.type = "text"; self.text = text

class MockToolUseBlock:
    def __init__(self, id, name, input):
        self.type = "tool_use"; self.id = id; self.name = name; self.input = input

class MockUsage:
    def __init__(self, i, o):
        self.input_tokens = i; self.output_tokens = o

class MockMessage:
    def __init__(self, stop_reason, content, usage):
        self.stop_reason = stop_reason; self.content = content; self.usage = usage

responses = iter([
    MockMessage(
        stop_reason="tool_use",
        content=[
            MockTextBlock("Let me search."),
            MockToolUseBlock(id="t1", name="search", input={"q": "ramen tokyo"}),
        ],
        usage=MockUsage(40, 20),
    ),
    MockMessage(
        stop_reason="end_turn",
        content=[
            MockTextBlock("Found Tokyo's best ramen, 2026 guide."),
        ],
        usage=MockUsage(50, 10),
    ),
])

def fake_create(messages):
    return next(responses)

def run_agent(question, max_iters):
    api_key = os.getenv("ANTHROPIC_API_KEY")
    if api_key is None:
        return {"ok": False, "error": "missing key"}

    messages = [{"role": "user", "content": question}]
    tokens_used = 0

    for i in range(1, max_iters + 1):
        response = fake_create(messages)
        tokens_used += response.usage.input_tokens + response.usage.output_tokens

        if response.stop_reason == "end_turn":
            text_parts = [b.text for b in response.content if b.type == "text"]
            return {
                "ok": True,
                "answer": " ".join(text_parts),
                "iters": i,
                "tokens": tokens_used,
            }

        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                output = TOOLS[block.name](**block.input)
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": output,
                })
        messages.append({"role": "assistant", "content": response.content})
        messages.append({"role": "user", "content": tool_results})

    return {"ok": False, "error": "capped", "iters": max_iters}

result = run_agent("find ramen tokyo", 5)
if result.get("ok"):
    print(f"ok={result['ok']} iters={result['iters']} tokens={result['tokens']} answer={result['answer']}")
else:
    print(f"ok={result['ok']} error={result['error']}")

