def bridge_mcp_tools(tools_list_response, mcp_call):
    tools = {}
    schemas = {}
    for tool_def in tools_list_response["result"]["tools"]:
        name = tool_def["name"]
        schemas[name] = tool_def["inputSchema"]
        def make_closure(tool_name):
            def call(**args):
                response = mcp_call(tool_name, args)
                text = response["result"]["content"][0]["text"]
                if response["result"]["isError"]:
                    text = f"TOOL_ERROR: {text}"
                return text
            return call
        tools[name] = make_closure(name)
    return tools, schemas

